<?php
require __DIR__.'/../inc/bootstrap.php';admin_required();ensure_visits_table();backfill_visit_countries();
$total=(int)db()->query('SELECT COUNT(*) FROM visits')->fetchColumn();$today=(int)db()->query('SELECT COUNT(*) FROM visits WHERE visited_at >= CURDATE()')->fetchColumn();$unique=(int)db()->query('SELECT COUNT(DISTINCT ip_address) FROM visits')->fetchColumn();$online=(int)db()->query("SELECT COUNT(DISTINCT visitor_id) FROM visits WHERE visited_at >= (NOW() - INTERVAL 5 MINUTE)")->fetchColumn();$countries=db()->query('SELECT country,COUNT(*) AS visits,COUNT(DISTINCT ip_address) AS visitors FROM visits GROUP BY country ORDER BY visits DESC LIMIT 50')->fetchAll();$visits=db()->query('SELECT ip_address,country,page,visited_at FROM visits ORDER BY visited_at DESC LIMIT 250')->fetchAll();
$pageTitle='Raporlar';$activeMenu='reports';require __DIR__.'/_header.php';
?><div class="page-head"><div><h1>Raporlar</h1><p>Ziyaretçi ve trafik özeti</p></div></div><section class="stats"><article class="card stat online"><span>Şu anda içeride</span><strong><?=number_format($online,0,',','.')?></strong><small>Son 5 dakika</small></article><article class="card stat"><span>Bugünkü ziyaret</span><strong><?=number_format($today,0,',','.')?></strong></article><article class="card stat"><span>Tekil IP</span><strong><?=number_format($unique,0,',','.')?></strong><small>Toplam <?=number_format($total,0,',','.')?> görüntülenme</small></article></section><section class="card" style="margin-bottom:20px"><h2>Ülke bazında ziyaretçiler</h2><div class="table-wrap"><table><thead><tr><th>Ülke</th><th>Görüntülenme</th><th>Tekil IP</th></tr></thead><tbody><?php foreach($countries as $r):?><tr><td><?=e($r['country'])?></td><td><?=$r['visits']?></td><td><?=$r['visitors']?></td></tr><?php endforeach?></tbody></table></div></section><section class="card"><h2>Son ziyaretler</h2><div class="table-wrap"><table><thead><tr><th>Tarih</th><th>IP adresi</th><th>Ülke</th><th>Sayfa</th></tr></thead><tbody><?php foreach($visits as $r):?><tr><td><?=e($r['visited_at'])?></td><td><?=e($r['ip_address'])?></td><td><?=e($r['country'])?></td><td><?=e($r['page'])?></td></tr><?php endforeach?></tbody></table></div></section><?php require __DIR__.'/_footer.php';?>
